content.query:
Usage
| where TimeGenerated {TimeRange:query}
| where IsBillable == true
| summarize TotalGB = sum(Quantity) / 1000
| extend EstimatedCost = TotalGB * {AnalyticsPrice}

Usage
| where TimeGenerated {TimeRange:query}
| where IsBillable == true
| summarize DailyGB = sum(Quantity) / 1000 by bin(TimeGenerated, 1d)
| summarize AvgDaily = avg(DailyGB)
| extend EstimatedMonthlyCost = AvgDaily * 30 * {AnalyticsPrice}

Usage
| where TimeGenerated {TimeRange:query}
| where IsBillable == true
| summarize DailyGB = sum(Quantity) / 1000 by bin(TimeGenerated, 1d)
| extend DailyCost = DailyGB * {AnalyticsPrice}

Usage
| where TimeGenerated {TimeRange:query}
| where IsBillable == true
| summarize GB = sum(Quantity) / 1000 by DataType
| extend Cost = GB * {AnalyticsPrice}
| top 10 by Cost desc

let RetentionDays = 90;
let ArchiveStart = ago(RetentionDays * 1d);
union withsource=_TableName *
| where TimeGenerated < ArchiveStart
| summarize ArchiveGB = sum(_BilledSize) / 1024 / 1024 / 1024
| extend ArchiveCost = ArchiveGB * {ArchivePrice}
| extend InteractiveCost = ArchiveGB * {RetentionPrice}
| extend MonthlySavings = InteractiveCost - ArchiveCost
| project 
    ['Archive Storage (GB)'] = round(ArchiveGB, 2),
    ['Archive Cost/Month (£0.02/GB)'] = round(ArchiveCost, 2),
    ['If Interactive (£0.10/GB)'] = round(InteractiveCost, 2),
    ['Monthly Savings (80%)'] = round(MonthlySavings, 2)

let DataLakeThreshold = ago(365d);
union withsource=_TableName *
| where TimeGenerated < DataLakeThreshold
| summarize DataLakeGB = sum(_BilledSize) / 1024 / 1024 / 1024
| extend ArchiveCost = DataLakeGB * {ArchivePrice}
| extend DataLakeCost = DataLakeGB * {DataLakePrice}
| extend Savings = ArchiveCost - DataLakeCost
| project DataLakeGB, ArchiveCost, DataLakeCost, Savings
